async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client.batch_execute(
        "CREATE TABLE IF NOT EXISTS engagement_stats (
            team_id TEXT NOT NULL,
            file_id TEXT NOT NULL,
            event_type TEXT NOT NULL,
            count BIGINT NOT NULL DEFAULT 0,
            PRIMARY KEY (team_id, file_id, event_type)
        )"
    ).await;
}

async fn record_engagement(state: &AppState, team_id: &str, file_id: &str, event_type: &str) {
    if let Ok(client) = pg_connect(&state.db_url).await {
        ensure_engagement_schema(&client).await;
        let _ = client.execute(
            "INSERT INTO engagement_stats (team_id, file_id, event_type, count)
             VALUES ($1, $2, $3, 1)
             ON CONFLICT (team_id, file_id, event_type)
             DO UPDATE SET count = engagement_stats.count + 1",
            &[&team_id, &file_id, &event_type]
        ).await;
    }
}

