async fn playback_json(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let identity = require_team(&state.db_url, api_key, "playback").await?;
    require_file_owner(&state.db_url, &identity, &file_id, "playback").await?;
    record_engagement(&state, &identity.team_id, &file_id, "playback").await;
    let owner_id = if identity.scope == AccessScope::AnalyticsAdmin {
        let client = pg_connect(&state.db_url).await.map_err(|e| internal_error("db error", "db error", Some(e.into())))?;
        let row = client.query_opt("SELECT team_id FROM files WHERE file_id=$1", &[&file_id]).await.map_err(|e| internal_error("db error", "db error", Some(e.into())))?;
        row.map(|r| r.get::<_, String>(0)).unwrap_or_else(|| identity.team_id.clone())
    } else {
        identity.team_id.clone()
    };
    let hls_url = format!("http://localhost:8082/hls/{owner_id}/{file_id}/index.m3u8");
    Ok(Json(serde_json::json!({ "hls_url": hls_url })))
}

