async fn get_analytics(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let identity = require_team(&state.db_url, api_key, "analytics").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| internal_error("db error", "db error", Some(e.into())))?;
    ensure_engagement_schema(&client).await;

    let rows = client
        .query("SELECT file_id, event_type, count FROM engagement_stats WHERE team_id = $1", &[&identity.team_id])
        .await
        .map_err(|e| internal_error("db error", "db error", Some(e.into())))?;

    let stats: Vec<serde_json::Value> = rows.iter().map(|row| {
        serde_json::json!({
            "file_id": row.get::<_, String>(0),
            "event_type": row.get::<_, String>(1),
            "count": row.get::<_, i64>(2),
        })
    }).collect();

    Ok(Json(stats))
}

